Workbook wb = WorkbookFactory.create(new FileInputStream("config.xlsx"));

// Read from QA config sheet
Sheet qaSheet = wb.getSheet("QA");
String qaUrl = qaSheet.getRow(0).getCell(1).getStringCellValue();

// Read from Prod config sheet
Sheet prodSheet = wb.getSheet("PROD");
String prodUrl = prodSheet.getRow(0).getCell(1).getStringCellValue();

System.out.println("QA URL: " + qaUrl);
System.out.println("Prod URL: " + prodUrl);
